import React from 'react';
import PropTypes from 'prop-types';
import { useListBoxSection } from '@react-aria/listbox';

import ListBoxItem from './ListBoxItem';
import { ListGroup } from '@andes/list';

/**
 * @typedef {Object} ListBoxGroupProp
 * @prop {string} [`aria-label`]
 * @prop {Object} [childNodes]
 * @prop {React.ReactNode} [rendered]
 * @prop {number} [index]
 * @prop {string} [textValue]
 * @prop {string} [type]
 * @prop {Omit<import('../../../list/lib/components/ListItem').ListItemProps, 'size' | 'component' | 'id'> &
 *  { children?: React.ReactElement | React.ReactElement[] } } [props]
 * @prop {object | string} [value]
 */

/**
 * @typedef {Object} ListGroupProps
 * @prop {{ role?: string }} [itemProps]
 * @prop {{ id?: string, 'aria-hidden'?: boolean }} [headingProps]
 * @prop {{ role?: string }} [groupProps]
 * @prop {React.ElementType} [component]
 * @prop {ListBoxGroupProp} group
 * @prop {string} listId
 * @prop {(
 *  event: React.MouseEvent<HTMLLIElement>
 * ) => void} [onClick]
 * @prop {(
 *  event: React.KeyboardEvent<HTMLLIElement> | React.MouseEvent<HTMLLIElement>,
 *  selectedValue: { value: string }
 * ) => void} [onSelect]
 */

/** @type {React.FunctionComponent<ListGroupProps & import('./ListBoxItem').ListBoxState>} */
const ListBoxGroup = ({ group, state, listId, ...otherProps }) => {
  const { rendered: heading, 'aria-label': ariaLabel, props: listGroupProps, index } = group;

  const { itemProps, headingProps, groupProps } = useListBoxSection({ heading, 'aria-label': ariaLabel });

  // override react-aria unique/random generated ids
  headingProps.id = `${listId}__group-heading-${index}`;
  groupProps['aria-labelledby'] = headingProps.id;

  return (
    <ListGroup
      label=""
      itemProps={itemProps}
      headingProps={headingProps}
      groupProps={groupProps}
      {...listGroupProps}
    >
      {// @ts-expect-error
      [...group.childNodes].map(groupNode =>
        <ListBoxItem key={groupNode.key} item={groupNode} state={state} {...otherProps} />,
      )
      }
    </ListGroup>
  );
};

ListBoxGroup.propTypes = {
  // group could be null according to how prop-types handles optional params
  group: PropTypes.shape({
    'aria-label': PropTypes.string.isRequired,
    childNodes: PropTypes.shape({
      'aria-label': PropTypes.string,
      props: PropTypes.shape({
        value: PropTypes.string,
      }),
      index: PropTypes.number,
      key: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
      type: PropTypes.string,
      value: PropTypes.string,
    }),
    rendered: PropTypes.string,
    index: PropTypes.number,
    textValue: PropTypes.string,
    type: PropTypes.string,
    props: PropTypes.shape({
      children: PropTypes.arrayOf(PropTypes.element.isRequired),
      component: PropTypes.string,
      id: PropTypes.string,
      label: PropTypes.string,
      size: PropTypes.oneOf(['small', 'medium', 'large']),
    }).isRequired,
  }).isRequired,
  // This was added because state is produced by a lib,
  // so the props can be different depending on the hook that is invoked.
  state: PropTypes.shape({
    collection: PropTypes.shape({}).isRequired,
    disabledKeys: PropTypes.shape({}).isRequired,
    selectionManager: PropTypes.shape({}).isRequired,
    selectedKey: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    setSelectedKey: PropTypes.func,
    selectedItem: PropTypes.shape({}),
  }).isRequired,
  listId: PropTypes.string.isRequired,
};

export default ListBoxGroup;
