import React, { isValidElement, useEffect, useRef, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { Image } from '@andes/image';
import ChevronRight20 from '@andes/icons/ChevronRight20';

import getVerifiedRightContent from '../utils/getVerifiedRightContent';
import { hasSlot } from '../utils/hasSlot';
import { getAttributesByListType } from '../utils/getAttributesByListType';

import { listItemNamespace } from '../constants';
import { LIST_ITEM_CONTENT_DISPLAY_NAME } from '../constants/components';
import { AVAILABLE_SIZES, MEDIUM, SMALL, primarySizes } from '../constants/layout';
import computeRightContent from '../utils/computeRightContent';
import { useListContext } from '../context/ListContext';

/**
 * @typedef {React.FunctionComponentElement<unknown>} ThumbnailComponent
 * @typedef {import('../../index').ImageContent} ImageType
 * @typedef {React.Dispatch<React.SetStateAction<undefined | number>>} PrimaryHeightDispatch
 * @typedef {import('../../index').ListItemContentProps} ListItemContentPublicProps
 */

/**
 * @typedef {Object} ListItemContentInternalProps
 * @prop {boolean} [addPrimaryLabel]
 * @prop {boolean} [baseList]
 * @prop {'a' | 'button'} [component]
 * @prop {Record<string, unknown>} [componentProps]
 * @prop {boolean} [chevron]
 * @prop {boolean} [legacyBehavior] If false, the slot content takes priority over layout properties.
 * @prop {string} [value]
 */

/** @typedef {ListItemContentPublicProps & ListItemContentInternalProps} ListItemContentProps */

// eslint-disable-next-line max-len
/** @type {React.FunctionComponent<ListItemContentProps>} */
const ListItemContent = (props) => {
  const {
    addPrimaryLabel: addLabel = false,
    baseList = false,
    chevron = false,
    children,
    component: Component = React.Fragment,
    componentProps = {},
    description = '',
    id,
    leftContent,
    legacyBehavior = false,
    maxLines,
    rightContent = '',
    rightContentPosition = 'top',
    size = MEDIUM,
    title = '',
    value,
  } = props;

  const { listType = 'standalone' } = useListContext();
  const attributes = getAttributesByListType(listType)();

  const hasDescription = description && size !== SMALL;
  const isThumbnail = isValidElement(leftContent)
    && (/** @type {ThumbnailComponent} */ (leftContent)?.type?.displayName) === 'Thumbnail';
  const leftContentHasSrc = /** @type {ImageType} */ (leftContent)?.src
    && typeof /** @type {ImageType} */ (leftContent).src === 'string';
  const computedRightContent = computeRightContent({ rightContent, rightContentPosition });
  const stringRightContent = typeof computedRightContent?.content === 'string';
  const centerRightContent = leftContentHasSrc || isThumbnail;
  const isSlotted = hasSlot(children, {
    title,
    description,
    rightContent: computedRightContent?.content || computedRightContent?.description,
  }, { legacyBehavior });

  /** @type {React.RefObject<HTMLSpanElement | null> | React.LegacyRef<HTMLLabelElement | null>} */
  const primaryTextRef = useRef(null);
  const [primaryHeight, setPrimaryHeight] = useState();

  useEffect(() => {
    if (!centerRightContent) {
      /** @type {PrimaryHeightDispatch} */ (setPrimaryHeight)(primaryTextRef.current?.clientHeight);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const primaryClassNames = classNames(`${listItemNamespace}-primary`, {
    [`${listItemNamespace}-primary--max-lines-${maxLines}`]: maxLines,
  });

  const secondColumnClassNames = classNames(`${listItemNamespace}-second-column`, {
    [`${listItemNamespace}-second-column-with-centered-text`]: centerRightContent && stringRightContent,
  });

  const tertiaryContainerClassNames = classNames(
    `${listItemNamespace}-tertiary-container`,
    `${listItemNamespace}-tertiary-container--${centerRightContent ? 'centered' : computedRightContent?.position}`,
  );

  const tertiaryClassNames = classNames(
    `${listItemNamespace}-tertiary`,
    `${listItemNamespace}-tertiary--${centerRightContent ? 'centered' : computedRightContent?.position}`,
  );

  const assetClassNames = classNames(`${listItemNamespace}-asset`, {
    [`${listItemNamespace}-asset--icon`]: !centerRightContent,
    [`${listItemNamespace}-asset--icon-one-line`]: !hasDescription
    && (primaryHeight && primaryHeight <= primarySizes[size]),
  });

  const chevronClassNames = classNames(
    `${listItemNamespace}-chevron`,
    `${listItemNamespace}-chevron--${centerRightContent ? 'centered' : computedRightContent?.position}`,
  );

  const getTitle = () => (addLabel
    ? (
      // eslint-disable-next-line jsx-a11y/click-events-have-key-events, jsx-a11y/no-noninteractive-element-interactions
      <label
        className={primaryClassNames}
        htmlFor={`${id}-selection-component-${value}`}
        ref={/** @type {React.LegacyRef<HTMLLabelElement>} */(primaryTextRef)}
        onClick={(event) => event.stopPropagation()}
        {...attributes?.title}
      >
        {title}
      </label>
    )
    : (
      <span
        className={primaryClassNames}
        ref={/** @type {React.MutableRefObject<HTMLSpanElement>} */ (primaryTextRef)}
        {...attributes?.title}
      >
        {title}
      </span>
    )
  );

  const getLeftContent = () => {
    if (leftContentHasSrc) {
      return (
        <Image
          {...(/** @type {ImageType} */ (leftContent))}
          className={`${listItemNamespace}-image`}
          aria-hidden
        />
      );
    }

    return /** @type {React.ReactNode} */ (leftContent);
  };

  if (isSlotted) {
    return (
      <Component {...componentProps}>
        <div className={`${listItemNamespace}-content`} id={addLabel ? `${id}-content-${value}` : `${id}-content`}>
          {children}
        </div>
        {chevron && (
          <div className={`${listItemNamespace}-chevron`} {...attributes?.chevron}>
            <ChevronRight20 color="currentColor" />
          </div>
        )}
      </Component>
    );
  }

  return (
    <>
      <Component {...componentProps}>
        {(title || description) && (
          <div
            className={`${listItemNamespace}-first-column`}
            id={`${id}-content`}
          >
            {leftContent && (
              <div
                className={assetClassNames}
                // @ts-expect-error: srLabel is a Thumbnail prop
                aria-hidden={!(isThumbnail && leftContent.props.srLabel) || undefined}
                {...attributes?.leftContent}
              >
                {getLeftContent()}
              </div>
            )}
            <div className={`${listItemNamespace}-text`}>
              {title && getTitle()}
              {hasDescription && (
                <span
                  className={`${listItemNamespace}-secondary`}
                  {...attributes?.description}
                >
                  {description}
                </span>
              )}
            </div>
          </div>
        )}
        {!baseList && (computedRightContent?.content || chevron) && (
          <div className={secondColumnClassNames}>
            {computedRightContent?.content && (
              <span
                className={tertiaryClassNames}
                {...attributes?.rightContent}
                id={`${id}-right-content`}
              >
                {getVerifiedRightContent(
                  // @ts-expect-error: Themes integration. Check typing.
                  computedRightContent?.content, size)}
              </span>
            )}
            {chevron && (
              <div className={chevronClassNames}>
                <ChevronRight20 color="currentColor" />
              </div>
            )}
          </div>
        )}
      </Component>
      {children}
      {baseList && (computedRightContent?.content || chevron) && (
        <div className={secondColumnClassNames}>
          {computedRightContent?.content && (
            <div
              className={tertiaryContainerClassNames}
              {...attributes?.rightContent}
              id={`${id}-right-content`}
            >
              <span className={tertiaryClassNames}>
                {getVerifiedRightContent(
                  // @ts-expect-error: Themes integration. Check typing.
                  computedRightContent?.content, size)}
              </span>
              {stringRightContent
                && computedRightContent?.description
                && size !== 'small' && (
                  <span className={`${listItemNamespace}-tertiary-description`}>
                    {computedRightContent?.description}
                  </span>
              )}
            </div>
          )}
          {chevron && (
            <div className={chevronClassNames} {...attributes?.chevron}>
              <ChevronRight20 color="currentColor" />
            </div>
          )}
        </div>
      )}
    </>
  );
};

ListItemContent.displayName = LIST_ITEM_CONTENT_DISPLAY_NAME;

ListItemContent.propTypes = {
  addPrimaryLabel: PropTypes.bool,
  baseList: PropTypes.bool,
  chevron: PropTypes.bool,
  children: PropTypes.node,
  component: PropTypes.oneOf(['button', 'a']),
  componentProps: PropTypes.shape({}),
  description: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  id: PropTypes.string,
  // leftContent could be null according to how prop-types handles optional params
  leftContent: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.shape({
      title: PropTypes.string,
      src: PropTypes.string,
      alt: PropTypes.string,
      src2x: PropTypes.string,
    }),
  ]),
  legacyBehavior: PropTypes.bool,
  maxLines: PropTypes.number,
  // rightContent could be null according to how prop-types handles optional params
  rightContent: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.shape({
      content: PropTypes.node,
      position: PropTypes.oneOf(['top', 'centered']),
    }),
  ]),
  rightContentPosition: PropTypes.oneOf(['top', 'centered']),
  size: PropTypes.oneOf(AVAILABLE_SIZES),
  title: PropTypes.oneOfType([PropTypes.node, PropTypes.string]),
  value: PropTypes.string,
};

export default ListItemContent;
