import includes from '@andes/common/build/utils/includes';

/**
 * @param {import('react').ReactElement} child
 * @param {string[]} [types]
 * @return {boolean}
 */
const isSupportedType = (child, types = []) => {
  if (!child) return false;

  return (
    // @ts-expect-error TS doesn't recognize that displayName is a prop of type
    includes(types, child.type?.displayName || child.type?.name)
    // @ts-expect-error TS doesn't recognize that displayName is a prop of type
    || includes(types, child.type?.wraps?.displayName || child.type?.name)
  );
};

export default isSupportedType;
