import isSupportedType from './isSupportedType';

/**
 * @param {Array<React.ReactElement>} children
 * @param {string} itemKey
 * @return {React.ReactElement | null}
 */
export const findItemInChildren = (children, itemKey) => {
  let findItem;

  children.forEach((child) => {
    // itemNodeGenerator uses value as the key (see more: https://github.com/melisource/fury_frontend-andes-ui/blob/master/packages/list/lib/generators/itemNodeGenerator.js#L29)
    if (isSupportedType(child, ['ListOption', 'FloatingMenuItem']) && (child?.props?.value === itemKey || child?.key === itemKey)) {
      findItem = child;
      return;
    }

    if (isSupportedType(child, ['ListGroup']) && child?.props?.children) {
      const foundItem = findItemInChildren(child.props.children, itemKey);

      if (foundItem) {
        findItem = foundItem;
      }
    }
  });

  return findItem || null;
};

