import React, { Children } from 'react';
import { ListGroup } from '@andes/list';
import ListOption from '../components/ListOption';
import isSupportedGroupType from '../utils/isSupportedGroupType';
import isSupportedItemType from '../utils/isSupportedItemType';

/** @param {React.ReactElement | React.ReactElement[]} children */
const useChildrenAdapter = (children) => Children.map(children, child => {
  if (isSupportedItemType(child)) return <ListOption {...child.props} />;

  if (isSupportedGroupType(child)) {
    const groupChildren = Children.map(child.props.children, item => {
      if (isSupportedItemType(item)) return <ListOption {...item.props} />;

      return item;
    });

    return <ListGroup {...child.props}>{groupChildren}</ListGroup>;
  }

  return child;
});

export default useChildrenAdapter;
