import React, { useRef, cloneElement, isValidElement, useMemo } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import warning from '@andes/common/build/utils/warning';
import { useOption } from '@react-aria/listbox';
import { mergeProps } from '@react-aria/utils';

import { ListBaseItem, ListItemContent } from '@andes/list';
import { hasImage } from '@andes/list/build/utils/hasImage';
import { hasSlot } from '@andes/list/build/utils/hasSlot';
import { isLegacyLeftContent } from '@andes/list/build/utils/isLegacyLeftContent';

import { ENTER, SPACE } from '@andes/common/build/constants/keyboardCodes';
import { WARNING_LIST_ITEM_CHILDREN, WARNING_LIST_ITEM_LEFT_CONTENT } from '../constants/warnings';
import { useListContext } from '@andes/list/build/context/ListContext';
import { getAttributesByListType } from '@andes/list/build/utils/getAttributesByListType';

/**
 * @typedef {Object} ListItemInternalProps
 * @prop {number} [index]
 * @prop {number} [groupIndex]
 * @prop {(
 *  event: React.KeyboardEvent<HTMLLIElement> | React.MouseEvent<HTMLLIElement>,
 *  selectedValue: { value: string }
 * ) => void} [onSelect]
 */

/**
 * @typedef {Object} ListBoxState
 * @prop {import('@react-stately/list').ListState<object>
 * | import('@react-stately/list').SingleSelectListState<object>} state
 */

/**
 * @typedef {Object} ListBoxItemChildrenItem
 * @prop {import('../../../list/lib/components/ListItem').ListItemProps & { value: string }} props
 * @prop {number | string} key
 * @prop {string | null} [aria-label]
 */

/**
 * @typedef {Object} ListBoxItemProps
 * @prop {ListBoxItemChildrenItem} item
 * @prop {React.ReactNode} [selectionComponent]
 * @prop {'large' | 'medium' | 'small'} [size]
 * @prop {(
 *  event: React.MouseEvent<HTMLLIElement>,
 *  itemValue?: string
 * ) => void} [onClick]
 * @prop {(
 *  event: React.KeyboardEvent<HTMLLIElement> | React.MouseEvent<HTMLLIElement>,
 *  selectedValue: { value: string }
 * ) => void} [onSelect]
 */

/** @type {React.FunctionComponent<ListBoxItemProps & ListBoxState>} */
const ListBoxItem = ({ item, state, ...otherProps }) => {
  const { key, props: listItemProps } = item;

  const { listType } = useListContext();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const { selection } = useMemo(() => getAttributesByListType(listType)(), []);

  const itemSelectionRef = useRef(null);

  const { optionProps, isSelected: selected } = useOption({ key }, state, itemSelectionRef);

  const inheritedProps = {
    ...listItemProps,
    key,
    selected,
  };

  const itemClassName = classNames(classNames, {
    'andes-list__item-with-selection-component': !!otherProps.selectionComponent,
  });

  const { onClick, onKeyDown, ...otherOptionProps } = optionProps;
  const { onSelect, ...otherOtherProps } = otherProps;

  /** @param {React.MouseEvent<HTMLLIElement>} e */
  const onClickHandler = e => {
    const { disabled, value, onSelect: inheritedOnSelect } = inheritedProps;
    const { onClick: inheritedOnClick } = otherProps;

    if (!disabled) {
      if (typeof inheritedOnClick === 'function') inheritedOnClick(e, value);
      if (typeof onClick === 'function') onClick(e);

      if (typeof inheritedOnSelect === 'function') inheritedOnSelect(e, { value });
      if (typeof onSelect === 'function') onSelect(e, { value });
    }
  };

  /** @type {React.KeyboardEventHandler<HTMLLIElement>} */
  const handleOnKeyDown = (event) => {
    if (typeof onKeyDown === 'function') onKeyDown(event);

    if (event.code === ENTER || event.code === SPACE) {
      // @ts-expect-error We are assigning a KeyboardEvent to a MouseEvent
      onClickHandler(event);
    }
  };

  const getCheckbox = () => {
    const { selectionComponent: Check } = otherProps;

    return isValidElement(Check) ? (
      <div
        {...selection}
        className="andes-list__item-selection-control andes-listbox__item-selection-control"
      >
        {cloneElement(Check, {
          // @ts-expect-error: Themes integration. Check typing.
          checked: inheritedProps.selected, disabled: inheritedProps.disabled })}
      </div>
    ) : null;
  };

  const itemProps = { ...mergeProps(inheritedProps, otherOtherProps) };
  const {
    children,
    description,
    disabled,
    id,
    leftContent,
    maxLines,
    paddingSize,
    rightContent,
    rightContentPosition,
    size,
    title,
  } = itemProps;
  const hasDescription = !!description;
  const hasLeftContentImage = hasImage(leftContent);
  const isSlotted = hasSlot(children, {
    title,
    description,
    rightContent,
  }, { legacyBehavior: true });
  const itemCustomEventsHandlers = { onClick: onClickHandler, onKeyDown: handleOnKeyDown };

  // @deprecate Warning from: 9.0.0
  warning(!(children && (title || description || rightContent)), WARNING_LIST_ITEM_CHILDREN);

  // @deprecate [leftContent] - Warning from: 9.0.0
  const legacyLeftContent = isLegacyLeftContent(leftContent);
  warning(!legacyLeftContent, WARNING_LIST_ITEM_LEFT_CONTENT);

  return (
    <ListBaseItem
      className={itemClassName}
      id={id}
      ref={itemSelectionRef}
      disabled={disabled}
      selected={selected}
      hasDescription={hasDescription}
      hasLeftContentImage={hasLeftContentImage}
      paddingSize={paddingSize}
      size={size}
      slotted={isSlotted}
      {...otherOptionProps}
      {...itemCustomEventsHandlers}
    >
      {getCheckbox()}
      <ListItemContent
        {...itemProps}
        key={key}
        title={title}
        description={description}
        leftContent={leftContent}
        rightContent={rightContent}
        rightContentPosition={rightContentPosition}
        maxLines={maxLines}
        size={size}
        id={id || otherOptionProps?.id}
        // @ts-expect-error: internal props
        legacyBehavior
      >
        {children}
      </ListItemContent>
    </ListBaseItem>
  );
};

ListBoxItem.propTypes = {
  item: PropTypes.shape({
    'aria-label': PropTypes.string,
    props: PropTypes.shape({
      value: PropTypes.string.isRequired,
      children: PropTypes.node,
      leftContent: PropTypes.node,
    }).isRequired,
    index: PropTypes.number.isRequired,
    key: PropTypes.oneOfType([PropTypes.number, PropTypes.string]).isRequired,
    type: PropTypes.string,
    value: PropTypes.string,
  }).isRequired,
  selectionComponent: PropTypes.element,
  // This was added because state is produced by a lib,
  // so the props can be different depending on the hook that is invoked.
  state: PropTypes.shape({
    collection: PropTypes.shape({}).isRequired,
    disabledKeys: PropTypes.shape({}).isRequired,
    selectionManager: PropTypes.shape({}).isRequired,
    selectedKey: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
    setSelectedKey: PropTypes.func,
    selectedItem: PropTypes.shape({}),
  }).isRequired,
  side: PropTypes.oneOf(['left', 'right']),
  size: PropTypes.oneOf(['small', 'medium', 'large']),
  onClick: PropTypes.func,
  onSelect: PropTypes.func,
};

export default ListBoxItem;
