import { trackCustomization, senderMetrics } from '@andes/common/build/metrics';

const METRIC_COMPONENT = 'Floating-Menu';

/**
 * @param {Partial<import('../..').FloatingMenuProps>} componentProps
 */
const isSlotted = ({ topContent, bottomContent, search }) =>
  (typeof topContent !== 'undefined' && !search)
  || typeof bottomContent !== 'undefined';

const metrics = senderMetrics(trackCustomization);

export const FloatingMenuMetrics = {
  SSR: [metrics?.sendSlots?.(METRIC_COMPONENT, isSlotted)],
};
