/** @typedef {import ('../..').ListItemProps['leftContent']} LeftContent */
/** @typedef {import('../..').DeprecatedImage} DeprecatedImage */

/**
 * @param {LeftContent} leftContent
 * @returns {boolean}
 */
export const isLegacyLeftContent = (leftContent) => {
  const legacyLeftContent = /** @type {DeprecatedImage} */ (leftContent)?.title
    || /** @type {DeprecatedImage} */ (leftContent)?.src
    || /** @type {DeprecatedImage} */ (leftContent)?.alt
    || /** @type {DeprecatedImage} */ (leftContent)?.src2x;

  return !!legacyLeftContent;
};
