import React, { useMemo } from 'react';
import PropTypes from 'prop-types';
import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';
import getListItemClassNames from '../utils/getListBaseItemClassNames';
import { LIST_BASE_ITEM_DISPLAY_NAME } from '../constants/components';
import { AVAILABLE_PADDING_SIZE, AVAILABLE_SIZES, MEDIUM } from '../constants/layout';
import { DEPRECATED_PADDING_SIZES_WARNINGS, WARNING_LIST_BASE_ITEM } from '../constants/warnings';
import { useListContext } from '../context/ListContext';
import { getAttributesByListType } from '../utils/getAttributesByListType';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';

/** @typedef {React.ComponentProps<typeof import('../..').ListBaseItem>} ListBaseItemProps */

/** @type {React.FunctionComponent<ListBaseItemProps>} */
const ListBaseItem = (props) => {
  const {
    children,
    className,
    component: Component = 'li',
    disabled,
    forwardedRef,
    hasDescription,
    hasLeftContentImage,
    interactive,
    paddingSize,
    selected,
    size = MEDIUM,
    slotted = false,
    srLabel,
    disableSelection = false,
    checked = false,
    ref,
    ...other
  } = /** @type {ListBaseItemProps} */ (props);

  const { listType = 'standalone' } = useListContext();

  // @deprecate [component] - Warning from: 9.0.0
  warning(Component === 'li', WARNING_LIST_BASE_ITEM);

  // @deprecate [paddingSize as string] - Warning from: 9.0.0
  if (typeof paddingSize === 'string') {
    warning(
      !includes(Object.keys(DEPRECATED_PADDING_SIZES_WARNINGS), paddingSize),
      DEPRECATED_PADDING_SIZES_WARNINGS[paddingSize],
    );
  }

  const listItemClassNames = getListItemClassNames({
    className,
    disabled,
    hasDescription,
    hasLeftContentImage,
    interactive,
    paddingSize,
    selected,
    size,
    slotted,
  });

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const { item } = useMemo(() => getAttributesByListType(listType)({ size }), [size]);

  return (
    <Component
      className={listItemClassNames}
      ref={ref}
      {...other}
      {...item}
      {...computeDataAndesState({
        checked: /** @type {boolean} */ (checked || false),
        disabled: /** @type {boolean} */ (disabled || disableSelection || false),
        selected,
      })}
    >
      {children}
    </Component>
  );
};

ListBaseItem.displayName = LIST_BASE_ITEM_DISPLAY_NAME;

ListBaseItem.propTypes = {
  checked: PropTypes.bool,
  children: PropTypes.node,
  className: PropTypes.string,
  component: PropTypes.oneOf(['li', 'div']),
  disabled: PropTypes.bool,
  disableSelection: PropTypes.bool,
  hasDescription: PropTypes.bool,
  hasLeftContentImage: PropTypes.bool,
  interactive: PropTypes.bool,
  paddingSize: PropTypes.oneOf(AVAILABLE_PADDING_SIZE),
  selected: PropTypes.bool,
  size: PropTypes.oneOf(AVAILABLE_SIZES),
  slotted: PropTypes.bool,
};

export default ListBaseItem;
