import { Children } from 'react';
import warning from '@andes/common/build/utils/warning';

/** @typedef {{ type: string; element: import('react').ReactNode }} ChildNodeItem */

/** @typedef {import('./generators').NativeProps} NativeProps */

/**
 * @typedef {import('../../index').ListGroupProps} ListGroupProps
 */

/** @param {ListGroupProps & NativeProps} props */
const hasChildNodes = ({ label, children }) => label && Children.count(children) > 0;

/** @param {ListGroupProps & NativeProps} props */
const groupNodeGenerator = function* getCollectionNode(props) {
  const { children, label, 'aria-label': ariaLabel } = props;
  const rendered = label || children;
  const textValue = (typeof rendered === 'string' ? rendered : '') || ariaLabel || '';

  warning(
    textValue,
    '<ListGroup> needs some plain text contents for accessibility reasons. Please add a `label` or `aria-label` prop.',
  );

  yield {
    type: 'section',
    props,
    rendered,
    textValue,
    'aria-label': ariaLabel || label,
    hasChildNodes,
    * childNodes() {
      if (label) {
        /** @type {ChildNodeItem[]} */
        const items = [];

        Children.forEach(children, child => {
          items.push({ type: 'item', element: child });
        });

        yield* items;
      }
    },
  };
};

export default groupNodeGenerator;
