/* This component was internally added in order to avoid circular dependencies */
import React, { useEffect, useMemo, useRef, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useAndesContext } from '@andes/context';
import { useThemeContext } from '@andes/themes';
import { FocusRing } from '@react-aria/focus';
import { VisuallyHidden } from '@andes/visually-hidden';
import warning from '@andes/common/build/utils/warning';
import Close16 from '@andes/icons/Close16';
import Search16 from '@andes/icons/Search16';
import Close20 from '@andes/icons/Close20';
import Search20 from '@andes/icons/Search20';

import { formNamespace, namespace, namespaceMenuSearch } from '../constants/common';
import { WARNING_SEARCHBOX_DISABLED } from '../constants/warnings';

import enTranslations from '../../translations/en/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';
import zhCNTranslations from '../../translations/zh-CN/messages.json';

/**
 * This types do not pick from @andes/search-box to avoid circular dependencies
 * @typedef {Object} SearchboxProps
 * @prop {string} [className]
 * @prop {string} [defaultValue]
 * @prop {React.InputHTMLAttributes<HTMLInputElement>} [inputProps]
 * @prop {(event: React.ChangeEvent<HTMLInputElement>) => void} [onChange]
 * @prop {(event: React.KeyboardEvent<HTMLButtonElement> | React.MouseEvent<HTMLButtonElement>) => void} [onClear]
 * @prop {(event: React.KeyboardEvent<HTMLInputElement>) => void} [onKeyDown]
 * @prop {string} [placeholder]
 * @prop {'large' | 'small'} [size]
 * @prop {string} [srLabel]
 * @prop {string} [value]
 * @prop {React.RefObject<HTMLDivElement | null> | ((refElement: HTMLDivElement | null) => void)} [ref]
 */

/** @type {React.FunctionComponent<SearchboxProps>} */
const SearchBox = ({
  className,
  defaultValue,
  inputProps = {},
  onChange,
  onClear,
  onKeyDown,
  placeholder,
  size = 'small',
  srLabel,
  value,
  ref,
}) => {
  const { device, i18n } = useAndesContext(
    '@andes/floating-menu',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCNTranslations },
  );

  const { getThemedComponentClasses, themeHash } = useThemeContext();

  /** @type {React.RefObject<HTMLInputElement | null>} */
  const inputRef = useRef(null);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isControlled = useMemo(() => typeof value !== 'undefined', []);
  const [focused, setFocused] = useState(false);
  const [showClear, setShowClear] = useState(false);
  const firstRender = useRef(true);

  const isWebMobileIOS = device?.osName === 'ios';

  warning(!inputProps?.disabled, WARNING_SEARCHBOX_DISABLED);

  useEffect(() => {
    if (!isControlled && defaultValue) {
      setShowClear(true);
    }
    firstRender.current = false;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (isControlled) {
      const showClearButton = !!value && value?.length > 0;
      setShowClear(showClearButton);
    }
  }, [isControlled, value, setShowClear]);

  useEffect(() => {
    if (focused) {
      inputRef.current?.focus();
    }
  }, [focused]);

  const SearchIcon = () => {
    if (size === 'small') {
      return <Search16 color="currentColor" />;
    }
    return <Search20 color="currentColor" />;
  };

  const CloseIcon = () => {
    if (size === 'small') {
      return <Close16 color="currentColor" />;
    }
    return <Close20 color="currentColor" />;
  };

  /** @param {React.ChangeEvent<HTMLInputElement>} event */
  const handleChange = (event) => {
    const showClearButton = !!inputRef?.current?.value && inputRef?.current?.value.length > 0;
    setShowClear(showClearButton);
    if (typeof onChange === 'function') onChange(event);
  };

  /** @param {React.KeyboardEvent<HTMLButtonElement> | React.MouseEvent<HTMLButtonElement>} event */
  const handleClear = (event) => {
    event.preventDefault();
    if (!isControlled && inputRef.current) inputRef.current.value = '';

    // @ts-expect-error: We add value
    event.target.value = '';
    setShowClear(false);
    if (typeof onClear === 'function') onClear(event);
    // @ts-expect-error: We modify event
    if (typeof onChange === 'function') onChange(event);

    inputRef.current?.focus();
  };

  /** @param {React.FocusEvent<HTMLInputElement>} event */
  const handleBlur = (event) => {
    const { onBlur } = inputProps;
    setFocused(false);
    if (typeof onBlur === 'function') onBlur(event);
  };

  /** @param {React.FocusEvent<HTMLInputElement>} event */
  const handleFocus = (event) => {
    const { onFocus } = inputProps;
    setFocused(true);
    if (typeof onFocus === 'function') onFocus(event);
  };

  const dismissClassNames = classNames(`${formNamespace}__close-icon`, {
    [`${formNamespace}__close-icon-visible`]: showClear,
  });

  const wrapperClassNames = classNames(namespaceMenuSearch,
    `${namespaceMenuSearch}--size-${size}`,
    className, {
      [`${namespaceMenuSearch}--web-mobile-ios`]: isWebMobileIOS,
      [`${namespaceMenuSearch}--focused`]: focused,
    });

  return (
    <div ref={ref} className={getThemedComponentClasses?.('searchbox')} {...themeHash}>
      <FocusRing within isTextInput focusRingClass="focus-visible">
        <div
          className={wrapperClassNames}
          data-andes-searchbox
          data-andes-searchbox-variant="simple"
          data-andes-searchbox-size={size}
        >
          {/* eslint-disable-next-line jsx-a11y/label-has-associated-control */}
          <label>
            <VisuallyHidden>{srLabel || i18n.pgettext(namespace, 'Buscar')}</VisuallyHidden>
            <input
              {...inputProps}
              className={`${formNamespace}__field`}
              value={value}
              defaultValue={defaultValue}
              placeholder={placeholder || `${i18n.pgettext(namespace, 'Buscar')}`}
              onChange={handleChange}
              onBlur={handleBlur}
              onFocus={handleFocus}
              ref={inputRef}
              onKeyDown={onKeyDown}
              data-andes-searchbox-input
            />
          </label>
          <button
            className={dismissClassNames}
            onClick={handleClear}
            onMouseDown={handleClear}
            aria-label={`${i18n.pgettext(namespace, 'Borrar')}`}
            type="button"
            data-andes-searchbox-close
          >
            <CloseIcon />
          </button>
          <div
            className={`${formNamespace}__search-icon`}
            data-andes-searchbox-search
          >
            <SearchIcon />
          </div>
        </div>
      </FocusRing>
    </div>
  );
};

SearchBox.propTypes = {
  className: PropTypes.string,
  defaultValue: PropTypes.string,
  inputProps: PropTypes.shape({}),
  onChange: PropTypes.func,
  onClear: PropTypes.func,
  onKeyDown: PropTypes.func,
  placeholder: PropTypes.string,
  size: PropTypes.oneOf(['small', 'large']),
  srLabel: PropTypes.string,
  value: PropTypes.string,
};

SearchBox.displayName = 'SearchBox';

export default SearchBox;
