import { Children, cloneElement, useCallback, useEffect, useMemo, useState } from 'react';
import { SUPPORTED_GROUP_TYPES } from '../constants/components';
import { ESCAPE, ARROW_UP, ARROW_DOWN, ENTER, SPACE } from '@andes/common/build/constants/keyboardCodes';
import includes from '@andes/common/build/utils/includes';
import { SEARCH_BOX_SIZE, LIST_ITEM_SIZE, TYPE_MENU, TYPE_SELECT } from '../constants/layout';
import usePreventScroll from '@andes/common/build/hooks/usePreventScroll';

const listHoverClass = 'andes-floating-menu-item-hover';

/** @typedef {import('../../index').SearchConfigProps | boolean | undefined} searchConfig */

/**
 * @typedef {Object} componentSpecificProps
 * @prop {string} listId
 * @prop {string} id
 * @prop {searchConfig} searchConfig
 */

/**
 * @typedef {Object} componentInternalProps
 * @prop {import('@andes/popper').PopperProps['offset']} [offset]
 * @prop {import('@andes/popper').PopperProps['onMount']} [onMount]
 * @prop {import('@andes/popper').PopperProps['popperOptions']} [popperOptions]
 * @prop {import('react').CSSProperties} [style]
 */

/**
 * @param {import('react').RefObject<HTMLButtonElement | null>} triggerRef
 * @param {import('react').RefObject<HTMLUListElement | null>} menuRef
 * @param {import('react').RefObject<HTMLDivElement | null>} searchBoxRef
 * @param {import('../../index').FloatingMenuProps
 * & componentSpecificProps & componentInternalProps} componentProps
 */
const useFloatingMenu = (triggerRef, menuRef, searchBoxRef, componentProps) => {
  const {
    allowUnselect,
    bottomContent,
    children,
    defaultOpen,
    defaultValue,
    listId,
    menuMaxHeight,
    multiple,
    offset,
    onChange,
    onClose,
    onOpen,
    open,
    popperOptions,
    searchConfig,
    style,
    topContent,
    type,
    value,
    width,
  } = componentProps;

  const isGroup = useMemo(() => {
    if (!children) return false;

    const firstOption = Children.toArray(children)[0];
    // @ts-expect-error: We add displayName property
    return includes(SUPPORTED_GROUP_TYPES, firstOption?.type?.displayName);
  }, [children]);

  const [currentValues, setCurrentValues] = useState(value || defaultValue);
  const [isMenuVisible, setIsMenuVisible] = useState(false);
  const [searchItemFocused, setSearchItemFocused] = useState(/** @type {string | undefined} */ (undefined));
  const [searchText, setSearchText] = useState(typeof searchConfig === 'object' && searchConfig?.defaultValue);

  usePreventScroll({ isDisabled: type === TYPE_MENU || (type === TYPE_SELECT && !isMenuVisible) });

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isUncontrolled = useMemo(() => value === undefined, []);

  const hasTopSlot = typeof topContent !== 'undefined';
  const hasBottomSlot = typeof bottomContent !== 'undefined';
  const isSlotted = hasTopSlot || hasBottomSlot || !!searchConfig;
  const role = type === 'select' ? 'combobox' : undefined;

  useEffect(() => {
    if (!isUncontrolled) {
      setCurrentValues(value);
    }
  }, [value, isUncontrolled]);

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isOpenUncontrolled = useMemo(() => open === undefined, []);

  const isEffectiveOpen = isOpenUncontrolled ? isMenuVisible : (open ?? false);

  const ariaHasPopupValue = isSlotted || (type === 'menu' && !multiple) ? 'dialog' : 'listbox';

  /** @param {HTMLUListElement} menu */
  const getItemToFocus = (menu) => {
    const optionsList = Array.prototype.slice.call(menu.querySelectorAll('.andes-list__item'));

    if (optionsList.length) {
      let focusableOption;

      // Search first menu item with button or link when type menu
      if (type === TYPE_MENU) {
        focusableOption = optionsList[0].querySelector('.andes-list__item-action, .andes-list__item-anchor, .andes-list__item-actionable');

        if (focusableOption) return focusableOption;
      }

      // Search last navigated option when type select
      focusableOption = optionsList.find(option =>
        option.tabIndex === 0,
      );

      // Search selected option
      if (!focusableOption) {
        focusableOption = optionsList.find(option =>
          option.className.indexOf('andes-list__item--selected') !== -1,
        );
      }

      // default to first option
      if (!focusableOption) {
        [focusableOption] = optionsList;
      }

      return focusableOption;
    }

    return null;
  };

  /**
   * @param {import('react').KeyboardEvent | import('react').MouseEvent} event
   * @param {string | string[]} [values]
   */
  const handleSelectionChange = (event, values) => {
    const shouldAvoidUnselect = (
      !allowUnselect
      && !multiple
      && (values === undefined || !values?.length)
      && currentValues !== undefined
    );

    if (shouldAvoidUnselect) return;

    if (isUncontrolled) setCurrentValues(values);

    let newValue = values;
    if (!multiple && Array.isArray(values)) [newValue] = values;

    if (searchConfig) setSearchItemFocused((state) => (!Array.isArray(newValue) ? newValue : state));

    if (typeof onChange === 'function') onChange(event, newValue);
  };

  const setPopoverFocus = () => {
    if (searchConfig) {
      /* The focus is applied to the label element instead of the input
      due to the keybord focus styles that need to be added */
      const label = searchBoxRef?.current?.querySelector('label');
      setTimeout(() => label?.focus(), 0);
      return;
    }

    const menu = menuRef.current;
    if (menu) {
      const itemToFocus = getItemToFocus(menu);

      if (itemToFocus) {
        itemToFocus.focus();
        menu.scrollTop = itemToFocus.offsetTop - LIST_ITEM_SIZE;
      }
    }
  };

  /** @param {string} text */
  const onSearchChangeText = (text) => setSearchText(text);

  const fitsSearchValue = useCallback(
    (/** @type {import('react').ReactElement<import('../../index').FloatingMenuItemProps>} */ item) => {
      if (!searchText) return true;

      const optionText = item.props.title;

      if (typeof searchConfig === 'object' && typeof searchConfig.filterCondition === 'function') {
        return searchConfig.filterCondition(searchText, optionText, item);
      }

      return optionText && includes(optionText.toLowerCase(), searchText.toLowerCase());
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [searchText, typeof searchConfig === 'object' && searchConfig?.filterCondition]);

  const options = useMemo(() => {
    if (!children) return null;

    if (isGroup) {
      let index = 0;

      /** @type {import('react').ReactElement<import('../../index').FloatingMenuGroup>[] | null} */
      const groups = [];
      Children.forEach(children, (/** @type {React.ReactElement} */ group, groupIndex) => {
        /** @type {import('react').ReactComponentElement<import('../../index').FloatingMenuGroup>[] | null} */
        const newChildren = [];
        Children.forEach(group?.props.children, item => {
          if (fitsSearchValue(item)) {
            newChildren.push(cloneElement(item, { index, groupIndex }));
          }
          index += 1;
        });
        if (newChildren.length > 0) {
          groups.push(cloneElement(group, { children: newChildren }));
        }
      });

      return groups;
    }

    /** @type {import('react').ReactElement<import('../../index').FloatingMenuItemProps>[]} */
    const newChildren = [];

    Children.forEach(children, (/** @type {React.ReactElement} */ child, index) => {
      if (fitsSearchValue(child)) {
        newChildren.push(cloneElement(child, { index }));
      }
    });

    return newChildren;
  }, [children, isGroup, fitsSearchValue]);

  /**
   * @param {HTMLCollection | []} list
   * @param {number} itemSelected
   */
  const hoverElement = (list, itemSelected) => {
    /**
     * @param {HTMLCollection | HTMLUListElement[]} items
     * @param {number} i
     * @param {number} [index]
     */
    const addRemoveFocus = (items, i, index) => {
      if (items[i].classList.contains(listHoverClass)) {
        items[i].classList.remove(listHoverClass);
      }
      if (itemSelected === (index === undefined ? i : index)) {
        items[i].classList.add(listHoverClass);
      }
    };

    if (isGroup) {
      let index = 0;
      for (let j = 0; j < list.length; j += 1) {
        const groupItems = list[j].children[1].children;

        for (let i = 0; i < groupItems.length; i += 1) {
          addRemoveFocus(groupItems, i, index);
          index += 1;
        }
      }
      return;
    }

    for (let i = 0; i < list.length; i += 1) {
      addRemoveFocus(list, i);
    }
  };

  /** @param {import('react').KeyboardEvent} [event] */
  const onSearchFocus = (event) => {
    setTimeout(() => searchBoxRef.current?.focus(), 0);

    const list = isGroup
      // We use ts-ignore because VSCode throws an error that conflicts with the TS linter
      // @ts-ignore: There are issues present with Array.reduce. See: https://github.com/microsoft/TypeScript/issues/44063
      ? options?.reduce((
        /** @type {import('react').ReactElement[]} */ previousValue,
        /** @type {import('react').ReactElement} */ currentValue,
      ) => [...previousValue, ...currentValue.props.children], [])
      : options || [];

    if (!list) return;

    const listLength = list.length;

    setSearchItemFocused((state) => {
      let index = list
        .findIndex((/** @type {{ props: Partial<{ value: string }> }} */ { props }) => props.value === state);

      switch (event?.code) {
        case ARROW_DOWN:
          index += 1;
          break;
        case ARROW_UP:
          if (index === -1 || index === 0) {
            index = listLength - 1;
            break;
          }
          index -= 1;
          break;
        default:
          index = 0;
          break;
      }
      const focusIndex = index % listLength;
      hoverElement(menuRef?.current?.children || [], focusIndex);

      return list[focusIndex]?.props?.value;
    });
  };

  const getFocusedItem = () => searchItemFocused;

  useEffect(() => {
    /* Manage custom scroll for search */
    if (isMenuVisible && searchConfig && searchItemFocused !== undefined) {
      const menu = menuRef.current;

      if (menu) {
        const itemToScrollTop = document?.getElementById(`${listId}-option-${searchItemFocused}`);

        // If menuMaxHeight is undefined, calculations will result in NaN
        if (itemToScrollTop && menuMaxHeight) {
          const listHeight = menuMaxHeight - SEARCH_BOX_SIZE;
          const itemsToTop = Math.floor(listHeight / LIST_ITEM_SIZE) - 1;
          menu.scrollTop = itemToScrollTop.offsetTop - (itemsToTop * LIST_ITEM_SIZE);
        }
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [searchConfig, menuRef, searchItemFocused, listId, isMenuVisible]);

  /** @param {import('react').KeyboardEvent | import('react').MouseEvent} event */
  const onSearchSelectionChange = (event) => {
    if (!searchItemFocused) return;

    if ((multiple || allowUnselect) && Array.isArray(currentValues)) {
      if ((currentValues || []).indexOf(searchItemFocused) > -1) {
        handleSelectionChange(event, currentValues.filter((item) => item !== searchItemFocused));
        return;
      }
    }

    if (multiple) {
      handleSelectionChange(event, [...(currentValues || []), searchItemFocused]);
      return;
    }

    handleSelectionChange(event, [searchItemFocused]);
  };

  const resetSearchValues = () => {
    const label = searchBoxRef?.current?.querySelector('label');
    if (label?.control) {
      /** @type {HTMLElement & { value?: string }} */
      const labelControl = label.control;
      labelControl.value = '';
    }

    setSearchText('');
    if (typeof searchConfig === 'object' && typeof searchConfig.onChange === 'function') searchConfig.onChange('');
  };

  /** @param {import('react').MouseEvent<HTMLButtonElement> | import('react').KeyboardEvent<HTMLButtonElement>} event */
  const openMenu = (event) => {
    setIsMenuVisible(true);
    if (!hasTopSlot) {
      setTimeout(setPopoverFocus, 0);
    }

    if (typeof onOpen === 'function') onOpen(event);
  };

  /**
   * @param {import('tippy.js').Instance | null} [_]
   * @param {boolean} [preventFocus]
   */
  const closeMenu = (_, preventFocus) => {
    const trigger = triggerRef.current;
    setIsMenuVisible(false);

    if (searchConfig) resetSearchValues();

    if (trigger && !preventFocus) setTimeout(() => trigger.focus(), 0);
    if (typeof onClose === 'function') onClose();
  };

  /** @param {import('tippy.js').Instance | null} _ */
  const handleClickOutside = (_) => {
    closeMenu(_, true);
  };

  /** @param {import('react').MouseEvent<HTMLButtonElement>} event */
  const toggleMenu = (event) => {
    if (isOpenUncontrolled) {
      if (isMenuVisible) {
        closeMenu();
      } else {
        openMenu(event);
      }
      return;
    }

    if (open) {
      if (typeof onClose === 'function') onClose();
    } else if (typeof onOpen === 'function') {
      onOpen(event);
    }
  };

  useEffect(() => {
    if (defaultOpen) setTimeout(openMenu, 0);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!isOpenUncontrolled) {
      if (open) {
        setTimeout(openMenu, 0);
      } else if (isMenuVisible) {
        closeMenu();
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  const getMenuMaxHeightRelatedStyles = () => {
    if (!menuMaxHeight) return {};

    return {
      maxHeight: menuMaxHeight,
      overflowY: /** @type {'auto'} */ ('auto'),
    };
  };


  /** @param {import('react').KeyboardEvent<HTMLButtonElement>} event */
  const handleOpenPopup = (event) => {
    event.preventDefault();
    if (isOpenUncontrolled) {
      openMenu(event);
      return;
    }
    if (typeof onOpen === 'function') onOpen(event);
  };

  const handleClosePopup = () => {
    if (isOpenUncontrolled) {
      closeMenu();
      return;
    }
    if (typeof onClose === 'function') onClose();
  };

  /** @param {import('react').KeyboardEvent<HTMLButtonElement>} event */
  const handleTriggerKeyDown = (event) => {
    switch (event.code) {
      case ESCAPE:
        handleClosePopup();
        break;
      case ARROW_DOWN:
      case ARROW_UP:
        if (type === 'select') handleOpenPopup(event);
        break;
      case ENTER:
      case SPACE:
        handleOpenPopup(event);
        break;
      default:
        break;
    }
  };

  const getValuesArray = () => {
    if (Array.isArray(currentValues)) return currentValues;
    if (typeof currentValues === 'string' || typeof currentValues === 'number') return [currentValues];
    return [];
  };

  const getAriaControls = () => {
    if (type !== 'select') return undefined;

    if (!isEffectiveOpen) return undefined;

    if (role && isSlotted) {
      return `${componentProps?.id}-dialog`;
    }

    return `${componentProps?.id}-list`;
  };

  const menuProps = {
    visible: isMenuVisible,
    onSelectionChange: handleSelectionChange,
    options,
    selectedKeys: getValuesArray(),
    style: { ...getMenuMaxHeightRelatedStyles(), width, ...style },
    popperOptions,
    plugins: [
      {
        name: 'hideOnEsc',
        defaultValue: true,
        /** @param {{ popper: HTMLDivElement }} _ */
        fn({ popper }) {
          function localOnKeyDown(/** @type {KeyboardEvent} */ event) {
            if (event.key === ESCAPE) {
              handleClosePopup();
            }
          }
          return {
            onShow() {
              popper.addEventListener('keydown', localOnKeyDown);
            },
            onHide() {
              popper.removeEventListener('keydown', localOnKeyDown);
            },
          };
        },
      },
    ],
    offset,
    onClickOutside: isOpenUncontrolled ? handleClickOutside : onClose,
    closeMenu: isOpenUncontrolled ? closeMenu : onClose,
    onSearchFocus: searchConfig ? onSearchFocus : undefined,
    onSearchSelectionChange: searchConfig ? onSearchSelectionChange : undefined,
    onSearchChangeText: searchConfig ? onSearchChangeText : undefined,
    getFocusedItem: searchConfig ? getFocusedItem : undefined,
    onMount: searchConfig ? componentProps.onMount : undefined,
  };

  const triggerProps = {
    role,
    'aria-expanded': isMenuVisible,
    'aria-controls': getAriaControls(),
    'aria-haspopup': ariaHasPopupValue,
    onClick: toggleMenu,
    onKeyDown: handleTriggerKeyDown,
  };

  return { menuProps, triggerProps };
};

export default useFloatingMenu;
