import React from 'react';
import PropTypes from 'prop-types';
import { useId } from '@andes/context';
import warning from '@andes/common/build/utils/warning';
import ListBaseItem from './ListBaseItem';
import ListItemContent from './ListItemContent';
import { hasImage } from '../utils/hasImage';
import { hasSlot } from '../utils/hasSlot';
import { isLegacyLeftContent } from '../utils/isLegacyLeftContent';
import { listItemNamespace } from '../constants';
import { AVAILABLE_SIZES, AVAILABLE_PADDING_SIZE, MEDIUM } from '../constants/layout';
import { LIST_ACTION_ITEM_DISPLAY_NAME } from '../constants/components';
import {
  WARNING_LIST_ACTION_ITEM_ACTION,
  WARNING_LIST_ITEM_LEFT_CONTENT,
} from '../constants/warnings';
import { withTracker } from '@andes/with-tracker';
import { ListItemMetrics } from '../metrics';

/** @typedef {React.ComponentProps<typeof import('../..').ListActionItem>} ListActionItemPublicProps */

/**
 * @typedef {object} ListActionItemInternalProps
 * @prop {boolean} [legacyBehavior]
 * @prop {boolean} [legacyBehaviorSlot]
 * @prop {boolean} [chevron]
 * @prop {boolean} [selected]
 * @prop {boolean} [value]
 * @prop {number} [groupIndex]
 * @prop {number} [index]
 */

/** @typedef {ListActionItemPublicProps & ListActionItemInternalProps} ListActionItemProps */

/** @type {React.FunctionComponent<ListActionItemProps>} */
const ListActionItem = (props) => {
  const {
    chevron = true,
    children,
    className,
    description,
    disabled = false,
    href,
    id,
    leftContent,
    legacyBehavior,
    legacyBehaviorSlot,
    maxLines,
    onClick,
    paddingSize,
    rightContent,
    rightContentPosition,
    size = MEDIUM,
    target,
    title,
    // The properties 'value', 'groupIndex', and 'index' are extracted separately and not
    // included in 'rest'. This is because these properties are not used in the 'ListActionItem'
    // component. However, they are relevant for components such as 'FloatingMenuItem' and
    // 'DropdownItem', which support selection (listbox) or actionable items (ListActionItem). Therefore,
    // we extract and exclude them to maintain compatibility with the parent components' API requirements.
    // eslint-disable-next-line react/prop-types
    value,
    // eslint-disable-next-line react/prop-types
    groupIndex,
    // eslint-disable-next-line react/prop-types
    index,
    ref,
    ...other
  } = props;

  const componentId = useId(id);
  const hasDescription = !!description;
  const hasLeftContentImage = hasImage(leftContent);
  const isSlotted = hasSlot(
    children,
    { title, description, rightContent },
    { legacyBehavior: legacyBehavior || legacyBehaviorSlot },
  );

  // @deprecate [leftContent] - Warning from: 9.0.0
  const legacyLeftContent = isLegacyLeftContent(leftContent);
  warning(!legacyLeftContent, WARNING_LIST_ITEM_LEFT_CONTENT);

  warning(!!(href || onClick), WARNING_LIST_ACTION_ITEM_ACTION);

  // eslint-disable-next-line react/prop-types
  const listBaseItemDeprecatedProps = legacyBehavior ? { selected: props?.selected } : {};

  const getPrimaryAction = () => !legacyBehavior && (href
    ? (
      // False positive in the use of aria-labelledby on anchor elements.
      // See the related issue for more details:
      // https://github.com/jsx-eslint/eslint-plugin-jsx-a11y/issues/411
      // https://github.com/jsx-eslint/eslint-plugin-jsx-a11y/issues/974
      // eslint-disable-next-line jsx-a11y/anchor-has-content
      <a
        aria-labelledby={`${componentId}-content`}
        className={`${listItemNamespace}-actionable`}
        {...disabled ? { role: 'link', 'aria-disabled': true } : { href, target, onClick }}
      />
    )
    : (
      <button
        aria-labelledby={`${componentId}-content`}
        className={`${listItemNamespace}-actionable`}
        disabled={disabled}
        onClick={onClick}
        type="button"
      />
    )
  );

  const getLegacyWrapper = () => {
    if (!legacyBehavior || !(href || onClick)) return {};

    if (href) {
      return ({
        component: /** @type {'a' | 'button'} */ ('a'),
        componentProps: {
          className: `${listItemNamespace}-anchor`,
          onClick,
          target,
          ...disabled ? { role: 'link', 'aria-disabled': true } : { href },
        },
      });
    }

    return ({
      component: /** @type {'a' | 'button'} */ ('button'),
      componentProps: {
        className: `${listItemNamespace}-action`,
        disabled,
        onClick,
        type: 'button',
      },
    });
  };

  return (
    <ListBaseItem
      className={className}
      id={componentId}
      ref={ref}
      disabled={disabled}
      hasDescription={hasDescription}
      hasLeftContentImage={hasLeftContentImage}
      interactive={!legacyBehavior}
      paddingSize={paddingSize}
      size={size}
      slotted={isSlotted}
      {...listBaseItemDeprecatedProps}
      {...other}
    >
      {getPrimaryAction()}
      <ListItemContent
        title={title}
        description={description}
        leftContent={leftContent}
        rightContent={rightContent}
        rightContentPosition={rightContentPosition}
        maxLines={maxLines}
        size={size}
        baseList
        chevron={chevron}
        legacyBehavior={legacyBehavior}
        id={componentId}
        {...getLegacyWrapper()}
      >
        {children}
      </ListItemContent>
    </ListBaseItem>
  );
};

ListActionItem.displayName = LIST_ACTION_ITEM_DISPLAY_NAME;

ListActionItem.propTypes = {
  chevron: PropTypes.bool,
  children: PropTypes.node,
  className: PropTypes.string,
  component: PropTypes.oneOf(['li', 'div']),
  description: PropTypes.node,
  disabled: PropTypes.bool,
  href: PropTypes.string,
  id: PropTypes.string,
  leftContent: PropTypes.node,
  legacyBehavior: PropTypes.bool,
  legacyBehaviorSlot: PropTypes.bool,
  maxLines: PropTypes.number,
  onClick: PropTypes.func,
  paddingSize: PropTypes.oneOf(AVAILABLE_PADDING_SIZE),
  rightContent: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.shape({
      content: PropTypes.string,
      description: PropTypes.string,
    }),
  ]),
  rightContentPosition: PropTypes.oneOf(['top', 'centered']),
  size: PropTypes.oneOf(AVAILABLE_SIZES),
  target: PropTypes.oneOf(['_self', '_blank', '_parent', '_top']),
  title: PropTypes.node,
};

export default withTracker(ListActionItem, ListItemMetrics);

