import React, { cloneElement } from 'react';
import PropTypes from 'prop-types';
import FloatingMenuMultiple from './FloatingMenuMultiple';
import { List } from '@andes/list';
import { ListBox } from '@andes/listbox';
import { GROUP_DISPLAY_NAME } from '../constants/components';
import { namespace } from '../constants/common';
import FloatingMenuListSlotted from './FloatingMenuSlotted';


/**
 * @typedef {Object} FloatingMenuListProps
 * @prop {(() => void) | undefined} [closeMenu] - Function to close the menu
 * @prop {import('@andes/common').BasicI18nProps} i18n
 * @prop {string} id
 * @prop {boolean} [multiple]
 * @prop {(event: React.KeyboardEvent) => void} onKeyDown
 * @prop {(
 * event: React.KeyboardEvent | React.MouseEvent,
 * values: string | string[],
 * itemDetails?: { value?: string }
 * ) => void} onSelect
 * @prop {React.ReactElement[] | null} options
 * @prop {boolean} [search]
 * @prop {string[]} [selectedKeys]
 * @prop {string} srLabel
 * @prop {'menu' | 'select'} [type]
 * @prop {boolean} visible
 * @prop {React.ReactNode} [topContent]
 * @prop {React.ReactNode} [bottomContent]
 * @prop {string} [dialogSrLabel]
 */

/** @type {React.FunctionComponent<FloatingMenuListProps & import('@andes/common').WithRef<HTMLUListElement>>} */
const FloatingMenuList = ({
  closeMenu,
  bottomContent,
  i18n,
  id,
  multiple = false,
  onKeyDown,
  onSelect,
  options,
  search = false,
  selectedKeys,
  srLabel,
  topContent,
  type = 'menu',
  visible,
  dialogSrLabel,
  ref,
}) => {
  if (!options || !options.length) {
    return (
      <FloatingMenuListSlotted
        visible={visible}
        topContent={topContent}
        bottomContent={bottomContent}
        dialog={!search}
        id={id}
        dialogSrLabel={dialogSrLabel}
      >
        <div className={`${namespace}__no-results`} data-andes-floating-menu-no-result>
          {i18n.pgettext(namespace, 'No hay resultados')}
        </div>
      </FloatingMenuListSlotted>
    );
  }

  const commonProps = {
    id,
    ref,
    className: namespace,
    onKeyDown,
    srLabel,
  };

  if (multiple) {
    return (
      <FloatingMenuListSlotted
        visible={visible}
        topContent={topContent}
        bottomContent={bottomContent}
        dialog={!search}
        id={id}
        dialogSrLabel={dialogSrLabel}
      >
        <FloatingMenuMultiple
          {...commonProps}
          onSelect={onSelect}
          value={selectedKeys}
          shouldUseVirtualFocus={!!search}
        >
          {options}
        </FloatingMenuMultiple>
      </FloatingMenuListSlotted>
    );
  }

  if (type === 'select' || search) {
    const isSlotted = typeof topContent !== 'undefined' || typeof bottomContent !== 'undefined';

    return (
      <FloatingMenuListSlotted
        visible={visible}
        topContent={topContent}
        bottomContent={bottomContent}
        dialog={isSlotted && !search}
        id={id}
        dialogSrLabel={dialogSrLabel}
      >
        <ListBox
          {...commonProps}
          onSelect={onSelect}
          selectionMode={multiple ? 'multiple' : 'single'}
          selectedKeys={selectedKeys}
          shouldUseVirtualFocus={!!search}
        >
          {options}
        </ListBox>
      </FloatingMenuListSlotted>
    );
  }

  /**
   * @param {(evt: React.MouseEvent, value: string | string[]) => void} childOnSelect
   * @param {React.MouseEvent} event
   * @param {string | string[]} value
   */
  const handleMenuClick = (childOnSelect, event, value) => {
    if (typeof childOnSelect === 'function') childOnSelect(event, value);

    if (typeof onSelect === 'function') onSelect(event, value);
  };

  /** @param {React.ReactElement} item */
  const getItem = (item) => cloneElement(item, {
    /**
     * @param {React.MouseEvent} evt
     * @param {string | string[]} value
     */
    onClick: (evt, value) => handleMenuClick(item.props.onClick, evt, value),
    tabIndex: undefined,
  });

  return (
    <FloatingMenuListSlotted
      visible={visible}
      topContent={topContent}
      bottomContent={bottomContent}
      dialog
      id={id}
      dialogSrLabel={dialogSrLabel}
      closeMenu={closeMenu}
    >
      <List {...commonProps}>
        {React.Children.map(options, (child) => {
          // @ts-expect-error: we add displayName
          const isGroup = child?.type?.displayName === GROUP_DISPLAY_NAME;
          if (isGroup) {
            const items = React.Children.map(child.props.children, getItem);

            return cloneElement(child, { children: items });
          }

          return getItem(child);
        })}
      </List>
    </FloatingMenuListSlotted>
  );
};

FloatingMenuList.propTypes = {
  closeMenu: PropTypes.func,
  bottomContent: PropTypes.node,
  dialogSrLabel: PropTypes.string,
  i18n: PropTypes.shape({
    pgettext: PropTypes.func.isRequired,
  }).isRequired,
  id: PropTypes.string.isRequired,
  multiple: PropTypes.bool,
  onKeyDown: PropTypes.func.isRequired,
  onSelect: PropTypes.func.isRequired,
  options: PropTypes.arrayOf(PropTypes.element.isRequired).isRequired,
  search: PropTypes.bool,
  selectedKeys: PropTypes.arrayOf(PropTypes.string.isRequired),
  srLabel: PropTypes.string.isRequired,
  type: PropTypes.oneOf(['menu', 'select']),
  topContent: PropTypes.node,
  visible: PropTypes.bool.isRequired,
};

FloatingMenuList.displayName = 'FloatingMenuList';

export default FloatingMenuList;
